import os
import sys

try:
    import boto3
    from botocore.exceptions import BotoCoreError, ClientError, NoCredentialsError
except ImportError:
    print("Missing dependency: boto3")
    print("Install it with: pip install boto3")
    sys.exit(1)

BUCKET_NAME = "demo-bucket"

ACCESS_KEY = os.getenv("AWS_ACCESS_KEY_ID")
SECRET_KEY = os.getenv("AWS_SECRET_ACCESS_KEY")
SESSION_TOKEN = os.getenv("AWS_SESSION_TOKEN")
REGION = os.getenv("AWS_DEFAULT_REGION", "us-east-1")

if not ACCESS_KEY or not SECRET_KEY:
    print("AWS credentials not found.")
    print("Set AWS_ACCESS_KEY_ID and AWS_SECRET_ACCESS_KEY before running.")
    sys.exit(1)

def list_all_files(bucket_name: str) -> None:
    try:
        session = boto3.Session(
            aws_access_key_id=ACCESS_KEY,
            aws_secret_access_key=SECRET_KEY,
            aws_session_token=SESSION_TOKEN,
            region_name=REGION,
        )
        s3 = session.client("s3")

        paginator = s3.get_paginator("list_objects_v2")
        pages = paginator.paginate(Bucket=bucket_name)

        found = False
        for page in pages:
            for obj in page.get("Contents", []):
                found = True
                print(obj["Key"])

        if not found:
            print(f"No files found in bucket '{bucket_name}'.")

    except NoCredentialsError:
        print("Invalid or missing AWS credentials.")
        sys.exit(1)
    except ClientError as e:
        print(f"AWS client error: {e}")
        sys.exit(1)
    except BotoCoreError as e:
        print(f"AWS SDK error: {e}")
        sys.exit(1)
    except Exception as e:
        print(f"Unexpected error: {e}")
        sys.exit(1)

if __name__ == "__main__":
    list_all_files(BUCKET_NAME)